CREATE TABLE IF NOT EXISTS "User" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS "UserProfile" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "emergencyFund" INTEGER NOT NULL, "monthlyNecessaryExpense" INTEGER NOT NULL, "incomeStability" TEXT NOT NULL, "monthlyDebtPayment" INTEGER NOT NULL, "monthlyAfterTaxIncome" INTEGER NOT NULL, "otherAvailableFunds" INTEGER NOT NULL, "earliestUseDate" DATETIME NOT NULL, "goalUseDate" DATETIME NOT NULL, "delayTolerance" TEXT NOT NULL, "interimFundingProbability" INTEGER NOT NULL, "maxLossAmount" INTEGER NOT NULL, "maxLossRatio" REAL NOT NULL, "postLossFundingNeed" TEXT NOT NULL, "recoveryWaitMonths" INTEGER NOT NULL, "investmentYears" INTEGER NOT NULL, "productTypes" TEXT NOT NULL, "maxDrawdownExperience" TEXT NOT NULL, "marketCycleExperience" TEXT NOT NULL, "selfDecisionLevel" TEXT NOT NULL, "companionType" TEXT NOT NULL, "proactiveContactPreference" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "UserProfile_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE UNIQUE INDEX IF NOT EXISTS "UserProfile_userId_key" ON "UserProfile"("userId");
CREATE TABLE IF NOT EXISTS "InvestmentGoal" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "goalType" TEXT NOT NULL, "targetAmount" INTEGER NOT NULL, "targetMonths" INTEGER NOT NULL, "currentPreparedAmount" INTEGER NOT NULL, "monthlyInvestment" INTEGER NOT NULL, "oneTimeAdditional" INTEGER NOT NULL, "postponeScore" INTEGER NOT NULL, "amountAdjustScore" INTEGER NOT NULL, "fallbackScore" INTEGER NOT NULL, "consequenceScore" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "InvestmentGoal_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "Product" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "productType" TEXT NOT NULL, "historicalMaxDrawdown" REAL NOT NULL, "hasLockup" BOOLEAN NOT NULL, "lockupDays" INTEGER NOT NULL, "earliestRedeemDate" DATETIME, "redeemArrivalDays" INTEGER NOT NULL, "riskLevel" TEXT NOT NULL, "description" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS "Conversation" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "title" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "Conversation_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "Message" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT NOT NULL, "role" TEXT NOT NULL, "content" TEXT NOT NULL, "metadata" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Message_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT "Message_conversationId_fkey" FOREIGN KEY ("conversationId") REFERENCES "Conversation" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "AiCallLog" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "version" TEXT NOT NULL, "callType" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "AiCallLog_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "RecognitionResult" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "intent" TEXT NOT NULL, "emotion" TEXT NOT NULL, "executionStage" TEXT NOT NULL, "confidence" REAL NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ProfileRoutingLog" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ConflictEvent" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "conflictPairId" TEXT NOT NULL, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "overallConflictLevel" TEXT NOT NULL, "status" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ConflictInteraction" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "conflictPairId" TEXT NOT NULL, "action" TEXT NOT NULL, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ProfileUpdateProposal" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "conflictPairId" TEXT, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ProfileUpdateLog" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "conflictPairId" TEXT, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ComplianceCheckLog" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "conversationId" TEXT, "requestId" TEXT NOT NULL, "version" TEXT NOT NULL, "input" TEXT NOT NULL, "output" TEXT NOT NULL, "success" BOOLEAN NOT NULL, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
